import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';

const Home = () => {
    const [songs, setSongs] = useState([]);
    const [currentSong, setCurrentSong] = useState(null);
    const [isPlaying, setIsPlaying] = useState(false);
    const audioRef = useRef(null);

    useEffect(() => {
        const fetchSongs = async () => {
            try {
                const res = await axios.get('http://localhost:5000/api/songs');
                setSongs(res.data);
            } catch (err) { console.error(err); }
        };
        fetchSongs();
    }, []);

    // Tự động phát khi đổi bài
    useEffect(() => {
        if (currentSong && audioRef.current) {
            audioRef.current.play();
            setIsPlaying(true);
        }
    }, [currentSong]);

    const handlePlayPause = () => {
        if (isPlaying) {
            audioRef.current.pause();
        } else {
            audioRef.current.play();
        }
        setIsPlaying(!isPlaying);
    };

    const handleNext = () => {
        const currentIndex = songs.findIndex(s => s._id === currentSong._id);
        if (currentIndex < songs.length - 1) {
            setCurrentSong(songs[currentIndex + 1]);
        }
    };

    const handlePrev = () => {
        const currentIndex = songs.findIndex(s => s._id === currentSong._id);
        if (currentIndex > 0) {
            setCurrentSong(songs[currentIndex - 1]);
        }
    };

    return (
        <div style={{ padding: '20px', maxWidth: '800px', margin: '0 auto', paddingBottom: '150px' }}>
            <h2 style={{ textAlign: 'center', marginBottom: '30px' }}>DANH SÁCH BÀI HÁT</h2>
            
            <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
                {songs.map((song) => (
                    <div key={song._id} style={{
                        display: 'flex', alignItems: 'center', padding: '12px 20px', 
                        border: '1px solid #eee', borderRadius: '12px',
                        background: currentSong?._id === song._id ? '#f0f7ff' : '#fff',
                        justifyContent: 'space-between'
                    }}>
                        <div style={{ display: 'flex', alignItems: 'center' }}>
                            <img src={song.imageUrl ? `http://localhost:5000${song.imageUrl}` : 'https://via.placeholder.com/50'} 
                                 style={{ width: '50px', height: '50px', borderRadius: '8px', marginRight: '15px', objectFit: 'cover' }} />
                            <div style={{ textAlign: 'left' }}>
                                <div style={{ fontWeight: 'bold' }}>{song.title}</div>
                                <div style={{ fontSize: '13px', color: '#666' }}>{song.artist}</div>
                            </div>
                        </div>
                        <button onClick={() => setCurrentSong(song)} style={{ padding: '8px 20px', background: '#28a745', color: '#fff', border: 'none', borderRadius: '20px', cursor: 'pointer' }}>
                            Nghe nhạc
                        </button>
                    </div>
                ))}
            </div>

            {/* THANH ĐIỀU KHIỂN NHẠC XỊN */}
            {currentSong && (
                <div style={{
                    position: 'fixed', bottom: 0, left: 0, right: 0, 
                    background: '#181818', color: '#fff', padding: '15px 30px', 
                    display: 'flex', flexDirection: 'column', alignItems: 'center', zIndex: 1000,
                    boxShadow: '0 -5px 20px rgba(0,0,0,0.5)'
                }}>
                    <div style={{ marginBottom: '10px', fontSize: '14px' }}>
                        Đang phát: <b style={{ color: '#1db954' }}>{currentSong.title}</b> - {currentSong.artist}
                    </div>

                    <div style={{ display: 'flex', alignItems: 'center', gap: '30px', marginBottom: '10px' }}>
                        {/* Nút Lùi */}
                        <button onClick={handlePrev} style={controlBtnStyle}>⏮</button>
                        
                        {/* Nút Play/Pause ở giữa */}
                        <button onClick={handlePlayPause} style={{
                            ...controlBtnStyle, background: '#fff', color: '#000', 
                            width: '45px', height: '45px', borderRadius: '50%', fontSize: '20px'
                        }}>
                            {isPlaying ? '⏸' : '▶'}
                        </button>

                        {/* Nút Tiến */}
                        <button onClick={handleNext} style={controlBtnStyle}>⏭</button>
                    </div>

                    <audio 
                        ref={audioRef}
                        src={`http://localhost:5000${currentSong.songUrl}`} 
                        onEnded={handleNext} // Tự chuyển bài khi hết nhạc
                        style={{ width: '100%', maxWidth: '600px', height: '30px' }}
                    />
                </div>
            )}
        </div>
    );
};

// Style cho các nút điều khiển
const controlBtnStyle = {
    background: 'none', border: 'none', color: '#fff', 
    fontSize: '24px', cursor: 'pointer', transition: 'transform 0.2s'
};

export default Home;
